Here's a solid pattern using `HttpMessageHandler` fakes and `CancellationToken` testing:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Fake handler to control HttpClient behavior
    private static HttpClient CreateClient(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> handler)
    {
        return new HttpClient(new FakeHandler(handler));
    }

    private class FakeHandler : HttpMessageHandler
    {
        private readonly Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> _func;
        public FakeHandler(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> func) => _func = func;
        protected override Task<HttpResponseMessage> SendAsync(HttpRequestMessage request, CancellationToken ct)
            => _func(request, ct);
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        using var client = CreateClient((_, _) => Task.FromResult(
            new HttpResponseMessage(System.Net.HttpStatusCode.OK)
            {
                Content = new StringContent("hello")
            }));

        var fetcher = new DataFetcher(client);
        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnHttpFailure()
    {
        using var client = CreateClient((_, _) => Task.FromResult(
            new HttpResponseMessage(System.Net.HttpStatusCode.InternalServerError)));

        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // --- Cancellation tests ---

    [TestMethod]
    public async Task FetchAsync_ThrowsWhenAlreadyCancelled()
    {
        using var client = CreateClient((_, ct) =>
        {
            ct.ThrowIfCancellationRequested();
            return Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.OK));
        });

        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsWhenCancelledDuringRequest()
    {
        using var cts = new CancellationTokenSource();

        using var client = CreateClient(async (_, ct) =>
        {
            // Simulate slow network, then cancel mid-flight
            cts.Cancel();
            await Task.Delay(500, ct);
            return new HttpResponseMessage(System.Net.HttpStatusCode.OK);
        });

        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // --- Timeout via CancellationTokenSource.CancelAfter ---

    [TestMethod]
    public async Task FetchAsync_ThrowsOnTimeout()
    {
        using var client = CreateClient(async (_, ct) =>
        {
            await Task.Delay(TimeSpan.FromSeconds(10), ct); // simulate slow response
            return new HttpResponseMessage(System.Net.HttpStatusCode.OK);
        });

        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }
}
```

**Key patterns:**

- **Fake `HttpMessageHandler`** — avoids real HTTP and gives full control over responses, delays, and cancellation behavior.
- **Pre-cancelled token** — verifies the method checks cancellation eagerly.
- **Mid-flight cancellation** — the handler cancels the token during execution, simulating user abort.
- **Timeout** — `CancellationTokenSource(TimeSpan)` is the idiomatic .NET timeout mechanism; no `Task.WhenAny` hacks needed.
- All tests use `async Task` — MSTest natively awaits them and fails correctly on unobserved exceptions.
